#include <WiFi.h>

// Constants including WiFi credentials and API keys
#define WIFI_SSID "yourWiFi_SSID"
#define WIFI_PASSWORD "yourWiFi_Password"
#define SECRET_API_KEY "yourAPIKey"

// Function to connect to WiFi
void connectToWiFi() {
    Serial.begin(115200);
    WiFi.begin(WIFI_SSID, WIFI_PASSWORD);

    while (WiFi.status() != WL_CONNECTED) {
        delay(1000);
        Serial.println("Connecting to WiFi...");
    }

    Serial.println("Connected to WiFi");
}

// Function to connect to cloud service
void connectToCloud() {
    // Replace URL with your cloud service URL
    const char* cloud_service_url = "http://cloudservice.com";
    
    HTTPClient http;
    http.begin(cloud_service_url);
    http.addHeader("Content-Type", "application/json");
    http.addHeader("X-API-KEY", SECRET_API_KEY);

    int httpResponseCode = http.POST("{\"message\":\"IoT device connected to cloud\"}");

    if(httpResponseCode>0){
        Serial.print("HTTP Response code: ");
        Serial.println(httpResponseCode);
    }
    else {
        Serial.print("Error on sending POST: ");
        Serial.println(httpResponseCode);
    }

    http.end();
}

void setup() {
    connectToWiFi();
    delay(5000);    //Wait 5 seconds before connecting to cloud
    connectToCloud();
}

